#include <stdio.h>
#include <math.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long N,K,X; scanf("%lld %lld %lld",&N,&K,&X);
        if(X==0){
            long long minK=N;
            long long maxK=N*(N+1)/2;
            puts((K>=minK && K<=maxK)?"YES":"NO");
        }else{
            long long maxK=(N*N)/4; // floor division
            puts((K<=maxK)?"YES":"NO");
        }
    }
    return 0;
}

