import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it)); X = int(next(it))
        if X == 0:
            minK = N
            maxK = N * (N + 1) // 2
            out.append('YES' if minK <= K <= maxK else 'NO')
        else:
            maxK = (N * N) // 4
            out.append('YES' if K <= maxK else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

